24	const basePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
25	
26	const COMPONENT_TYPES = new Set(["rune"]);
27	const BLOCK_SIZE = 3;
28	const BLOCK_PRICE = 60;
29	
30	const itemsBasePremium = (items: Item[]): number => {
31	  const components = items.filter((i) => COMPONENT_TYPES.has(i.type));
32	  const mainItems = items.filter((i) => !COMPONENT_TYPES.has(i.type));
33	  let total = mainItems.reduce((sum, item) => sum + basePremium(item), 0);
34	  const byType: Record<string, number> = {};
35	  for (const c of components) byType[c.type] = (byType[c.type] ?? 0) + 1;
36	  for (const type of Object.keys(byType)) {
37	    const count = byType[type];
38	    if (count === BLOCK_SIZE) {
39	      total += BLOCK_PRICE;
40	    } else {
41	      total += count * basePremium({ type });
42	    }
43	  }
44	  return total;
45	};
46	
47	export const runScenario = (scenario: Scenario): unknown => {
48	  const results = scenario.steps.map((step) => {
49	    const items = step.items ?? [];
50	    const total = itemsBasePremium(items);
51	    return { premium: total + PROCESSING_FEE };
52	  });
53	  return { results };
54	};
